    /**
     * Convert latitude/longitude to 3D world coordinates
     *
     * @param {number} lat - Latitude in degrees (-90 to 90)
     * @param {number} lng - Longitude in degrees (-180 to 180)
     * @param {number} [radius=1.0] - Radius from globe center
     * @returns {THREE.Vector3} 3D position on the globe
     */
    latLngToWorld(lat, lng, radius = 1.0) {
        const latRad = lat * this.DEG2RAD;
        const lngRad = lng * this.DEG2RAD;

        const y = Math.sin(latRad) * radius;
        const x = Math.cos(latRad) * Math.sin(lngRad) * radius;
        const z = Math.cos(latRad) * Math.cos(lngRad) * radius;

        return new THREE.Vector3(x, y, z);
    },

    /**
     * Convert 3D world coordinates to latitude/longitude
     *
     * @param {THREE.Vector3|{x,y,z}} point - 3D position
     * @returns {{lat: number, lng: number}} Geographic coordinates
     */
    worldToLatLng(point) {
        // Normalize to unit sphere
        const length = Math.sqrt(point.x * point.x + point.y * point.y + point.z * point.z);
        const x = point.x / length;
        const y = point.y / length;
        const z = point.z / length;

        // Calculate lat/lng
        const lat = Math.asin(y) * this.RAD2DEG;
        const lng = Math.atan2(x, z) * this.RAD2DEG;

        return { lat, lng };
    },

    /**
     * Get the surface normal at a lat/lng position (points outward)
     *
     * @param {number} lat - Latitude in degrees
     * @param {number} lng - Longitude in degrees
     * @returns {THREE.Vector3} Normalized direction vector
     */
    getSurfaceNormal(lat, lng) {
        return this.latLngToWorld(lat, lng, 1.0).normalize();
    },

    /**
     * Calculate the great circle distance between two points (in degrees)
     *
     * @param {number} lat1 - First point latitude
     * @param {number} lng1 - First point longitude
     * @param {number} lat2 - Second point latitude
     * @param {number} lng2 - Second point longitude
     * @returns {number} Angular distance in degrees
     */
    greatCircleDistance(lat1, lng1, lat2, lng2) {
        const lat1Rad = lat1 * this.DEG2RAD;
        const lng1Rad = lng1 * this.DEG2RAD;
        const lat2Rad = lat2 * this.DEG2RAD;
        const lng2Rad = lng2 * this.DEG2RAD;

        const d = Math.acos(
            Math.sin(lat1Rad) * Math.sin(lat2Rad) +
            Math.cos(lat1Rad) * Math.cos(lat2Rad) * Math.cos(lng2Rad - lng1Rad)
        );

        return d * this.RAD2DEG;
    },

    /**
     * Interpolate between two points along a great circle
     *
     * @param {number} fromLat - Starting latitude
     * @param {number} fromLng - Starting longitude
     * @param {number} toLat - Ending latitude
     * @param {number} toLng - Ending longitude
     * @param {number} fraction - Interpolation fraction (0 to 1)
     * @returns {{lat: number, lng: number}} Interpolated coordinates
     */
    interpolateGreatCircle(fromLat, fromLng, toLat, toLng, fraction) {
        const lat1 = fromLat * this.DEG2RAD;
        const lng1 = fromLng * this.DEG2RAD;
        const lat2 = toLat * this.DEG2RAD;
        const lng2 = toLng * this.DEG2RAD;

        // Calculate angular distance
        const d = Math.acos(
            Math.sin(lat1) * Math.sin(lat2) +
            Math.cos(lat1) * Math.cos(lat2) * Math.cos(lng2 - lng1)
        );

        // Handle case where points are very close
        if (d < 0.0001) {
            return { lat: fromLat, lng: fromLng };
        }

        // Spherical interpolation coefficients
        const a = Math.sin((1 - fraction) * d) / Math.sin(d);
        const b = Math.sin(fraction * d) / Math.sin(d);

        // Interpolate in Cartesian coordinates
        const x = a * Math.cos(lat1) * Math.cos(lng1) + b * Math.cos(lat2) * Math.cos(lng2);
        const y = a * Math.cos(lat1) * Math.sin(lng1) + b * Math.cos(lat2) * Math.sin(lng2);
        const z = a * Math.sin(lat1) + b * Math.sin(lat2);

        // Convert back to lat/lng
        const lat = Math.atan2(z, Math.sqrt(x * x + y * y)) * this.RAD2DEG;
        const lng = Math.atan2(y, x) * this.RAD2DEG;

        return { lat, lng };
    },

    /**
     * Get multiple points along a great circle path
     *
     * @param {number} fromLat - Starting latitude
     * @param {number} fromLng - Starting longitude
     * @param {number} toLat - Ending latitude
     * @param {number} toLng - Ending longitude
     * @param {number} segments - Number of segments
     * @returns {Array<{lat: number, lng: number}>} Array of points along the path
     */
    getGreatCirclePath(fromLat, fromLng, toLat, toLng, segments) {
        const points = [];
        for (let i = 0; i <= segments; i++) {
            const t = i / segments;
            points.push(this.interpolateGreatCircle(fromLat, fromLng, toLat, toLng, t));
        }
        return points;
    },

    /**
     * Project a 3D point to screen coordinates
     *
     * @param {THREE.Vector3} point - 3D world position
     * @param {THREE.Camera} camera - Three.js camera
     * @param {number} width - Screen width
     * @param {number} height - Screen height
     * @returns {{x: number, y: number, visible: boolean}} Screen position and visibility
     */
    worldToScreen(point, camera, width, height) {
        const vector = point.clone();
        vector.project(camera);

        // Check if behind camera
        const visible = vector.z < 1;

        return {
            x: (vector.x * 0.5 + 0.5) * width,
            y: (-vector.y * 0.5 + 0.5) * height,
            visible: visible
        };
    },

    /**
     * Check if a point on the globe is visible from the camera
     * (not on the far side of the globe)
     *
     * @param {number} lat - Point latitude
     * @param {number} lng - Point longitude
     * @param {THREE.Camera} camera - Three.js camera
     * @returns {boolean} True if the point is on the visible hemisphere
     */
    isPointVisible(lat, lng, camera) {
        const pointDirection = this.getSurfaceNormal(lat, lng);
        const cameraDirection = camera.position.clone().normalize();

        // Dot product > 0 means the point faces the camera
        const dot = pointDirection.dot(cameraDirection);
        return dot > 0;
    },

    /**
     * Calculate the angle between the camera and a point on the globe
     * Used for edge detection (limb detection)
     *
     * @param {number} lat - Point latitude
     * @param {number} lng - Point longitude
     * @param {THREE.Camera} camera - Three.js camera
     * @returns {number} Dot product (-1 to 1, where 1 = directly facing camera)
     */
    getViewAngle(lat, lng, camera) {
        const pointDirection = this.getSurfaceNormal(lat, lng);
        const cameraDirection = camera.position.clone().normalize();
        return pointDirection.dot(cameraDirection);
    },

    /**
     * Get camera position as lat/lng/altitude
     *
     * @param {THREE.Camera} camera - Three.js camera
     * @returns {{lat: number, lng: number, altitude: number}} Camera position
     */
    getCameraLatLng(camera) {
        const pos = camera.position;
        const altitude = pos.length();
        const coords = this.worldToLatLng(pos);
        return {
            lat: coords.lat,
            lng: coords.lng,
            altitude: altitude
        };
    },

    /**
     * Position camera to look at a specific lat/lng
     *
     * @param {THREE.Camera} camera - Three.js camera
     * @param {number} lat - Target latitude
     * @param {number} lng - Target longitude
     * @param {number} altitude - Camera altitude (distance from center)
     */
    setCameraLatLng(camera, lat, lng, altitude) {
        const position = this.latLngToWorld(lat, lng, altitude);
        camera.position.copy(position);
        camera.lookAt(0, 0, 0);
    },

    /**
     * Normalize a vector
     *
     * @param {THREE.Vector3|{x,y,z}} vector
     * @returns {THREE.Vector3} Normalized vector
     */
    normalize(vector) {
        const length = Math.sqrt(vector.x * vector.x + vector.y * vector.y + vector.z * vector.z);
        if (length === 0) return new THREE.Vector3(0, 1, 0);
        return new THREE.Vector3(
            vector.x / length,
            vector.y / length,
            vector.z / length
        );
    },

    /**
     * Calculate cross product of two vectors
     *
     * @param {THREE.Vector3|{x,y,z}} a
     * @param {THREE.Vector3|{x,y,z}} b
     * @returns {THREE.Vector3} Cross product
     */
    cross(a, b) {
        return new THREE.Vector3(
            a.y * b.z - a.z * b.y,
            a.z * b.x - a.x * b.z,
            a.x * b.y - a.y * b.x
        );
    },

